// src/utils/guideAssets.ts
// Auto-generated — embedded PDF guides so no public/docs/ file placement is required.
// Opened as blob URLs to avoid React Router interception.

const USER_GUIDE_B64 = "";
const ADMIN_GUIDE_B64 = "";

function openPdfBlob(b64: string, filename: string) {
  const bytes = atob(b64);
  const arr   = new Uint8Array(bytes.length);
  for (let i = 0; i < bytes.length; i++) arr[i] = bytes.charCodeAt(i);
  const blob = new Blob([arr], { type: "application/pdf" });
  const url  = URL.createObjectURL(blob);
  const win  = window.open(url, "_blank");
  // Revoke after a short delay so the PDF has time to load
  if (win) setTimeout(() => URL.revokeObjectURL(url), 60_000);
}

export const openUserGuide  = () => openPdfBlob(USER_GUIDE_B64,  "PathScribe_User_Guide.pdf");
export const openAdminGuide = () => openPdfBlob(ADMIN_GUIDE_B64, "PathScribe_Admin_Guide.pdf");
